+// Return the workstation position for a given room type (character type)
+export function getWorkstationPosition(roomType: CharacterType): { x: number; y: number } {
+  // Positions are relative offsets within the room bounding box (0 to 1)
+  switch (roomType) {
+    case 'king':
+      return { x: 0.5, y: 0.35 }; // throne center-ish
+    case 'nobility':
+      return { x: 0.5, y: 0.58 }; // council table center
+    case 'knight':
+      return { x: 0.15, y: 0.25 }; // war room desk area
+    case 'squire':
+      return { x: 0.5, y: 0.6 }; // workshop bench area
+    case 'healer':
+      return { x: 0.5, y: 0.5 }; // sanctum center
+    case 'sentinel':
+      return { x: 0.5, y: 0.5 }; // watchtower center
+    case 'scribe':
+      return { x: 0.5, y: 0.5 }; // scriptorium center
+    case 'judge':
+      return { x: 0.5, y: 0.5 }; // tribunal center
+    case 'blacksmith':
+      return { x: 0.5, y: 0.5 }; // forge center
+    default:
+      return { x: 0.5, y: 0.5 };
+  }
+}
