+        // Determine target position based on agent state
+        let targetX: number;
+        let targetY: number;
+
+        if (agent.state === 'running') {
+          // Working: position at workstation furniture
+          const pos = getWorkstationPosition(slot.tier as CharacterType);
+          targetX = rx + roomW * pos.x;
+          targetY = ry + labelH + roomH * pos.y;
+        } else {
+          // Idle: random position within walkable area
+          const walkX = rx + roomW * 0.08;
+          const walkY = ry + labelH + roomH * 0.38;
+          const walkW = roomW * 0.84;
+          const walkH = roomH * 0.45;
+          // Seed random by agent id for consistent position per render
+          const seed = agent.id.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0);
+          const randX = ((seed * 9301 + 49297) % 233280) / 233280;
+          const randY = ((seed * 49297 + 9301) % 233280) / 233280;
+          targetX = walkX + randX * walkW;
+          targetY = walkY + randY * walkH;
+        }
+
+        // Smooth movement update
+        const cs = getCS(agent.id, targetX, targetY);
+        const speed = 0.1; // interpolation speed factor (0-1)
+        cs.x += (targetX - cs.x) * speed;
+        cs.y += (targetY - cs.y) * speed;
+
+        // Pass currentJob as work status to drawCharacter
+        const animState = agent.state as AnimState;
+        drawCharacter(rc.ctx, slot.tier as CharacterType, animState, cs.x, cs.y, charScale, frameCount, agent.id, agent.currentJob);
+        
+        // Name plate (below character)
+        const nameY = cs.y + 24 * charScale;
+        drawText(rc, agent.name, cs.x - 4, nameY, 9, COLORS.text);
+        // State badge
+        const stateColor = getStateColor(agent.state);
+        drawText(rc, agent.state, cs.x - 4, nameY + 12, 8, stateColor);
+      });
+
+      // Overflow badge
