+        const badgeY = ry + labelH + 8;
+        rc.ctx.fillStyle = '#4a2060';
+        rc.ctx.fillRect(badgeX, badgeY, 24, 14);
+        rc.ctx.strokeStyle = COLORS.gold;
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(badgeX, badgeY, 24, 14);
+        drawText(rc, `+${overflow}`, badgeX + 3, badgeY + 11, 9, COLORS.gold);
+      }
+
